// Bicep: Complete mode is set at deployment time, not in the template
// The template itself has no 'mode' property — mode is a deployment parameter

// main.bicep — this template will delete anything in the RG not declared here
// when deployed in Complete mode

param location string = resourceGroup().location
param vmName string

resource vm 'Microsoft.Compute/virtualMachines@2023-03-01' = {
  name: vmName
  location: location
  // ...
}

resource storage 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'stmyappprodeus2'
  location: location
  sku: { name: 'Standard_LRS' }
  kind: 'StorageV2'
}

// Any resource in the RG not listed above will be deleted in Complete mode.
// In Incremental mode (default), resources not listed here are untouched.
